-- Light Sled Sprint Push (light-sled-sprint-push)
UPDATE coaching.exercise SET
  name = 'Light Sled Sprint Push',
  description = 'Light Sled Sprint Push is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.',
  card_summary = 'Light Sled Sprint Push trains resisted acceleration with maximal intent and low enough load to stay fast. Use it when the session needs fresh explosiveness rather than loaded strength volume.',
  coach_language = 'Primary subrole: Acceleration Start Speed. Slot: resisted acceleration. Coach Light Sled Sprint Push as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.',
  athlete_language = 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.',
  movement_family = 'Acceleration / First-Step Output',
  primary_phase_key = 'output',
  phase_subrole = 'acceleration_start_speed',
  primary_order_slot = 'resisted_acceleration',
  default_sets = 3,
  default_reps = 3,
  default_work_seconds = 8,
  default_rest_seconds = 90,
  est_seconds_per_set = 105,
  movement_requirements = '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","shoulder_horizontal_flexion","elbow_extension","trunk_bracing"],"primary_tissues":["glutes","hamstrings","hip_flexors","quadriceps","calves","achilles_tendon"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Light Sled Sprint Push is an Output-phase explosiveness drill for resisted acceleration with maximal intent and low enough load to stay fast. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set a light sled load that allows fast acceleration mechanics, not a slow grind.","Mark a short lane of 5-15 yards with cones.","Confirm clear space and a stable surface before each effort."],"execution_steps":["Set the body angle and brace before the start.","Drive aggressively through the first three steps with intent and posture.","Shut down after the target distance and rest fully before repeating."],"coach_cues":["Push the ground back.","Win the first three steps.","Stay low without folding.","Full reset, then repeat.","Light Sled Sprint Push: quality beats quantity."],"breathing_cues":["Brace before the explosive effort.","Exhale naturally through the burst; do not hold breath across repeated reps.","Use the walk-back or reset time to restore calm breathing."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version.","Loading the sled too heavy and changing the drill into a slow strength push."],"quality_gate":["Rep looks fast, crisp, and intentional from start to finish.","Athlete can explain the target direction, cue, or landing outcome.","No pain, no uncontrolled collapse, and no visible drop-off in speed across the set."],"stop_signs":["Pain, limping, dizziness, or apprehension.","Step rate slows enough that the push becomes a grind.","Athlete cannot recover enough to produce another high-speed rep."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Heavy lower-body strength","Acceleration sprints","Sport skill work","Conditioning block"],"pairs_well_after":["Dynamic warm-up","Landing prep","Sprint mechanics","Trunk activation"],"good_for_sessions":["sprint_prep","power_development","speed_development"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears during takeoff, landing, sprinting, throwing, bracing, or contact.","Athlete cannot control the lower-level version.","The session already created enough fatigue that speed or landing quality is compromised.","Coach intends to use the drill as conditioning instead of Output."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex explosiveness demo recommended","Vortex Exercise Card Authoring Guide: Output sequencing and dose rules","NSCA-style plyometric, sprint, and medicine-ball technique reference"],"internal_notes":["Film Light Sled Sprint Push from front/side where useful.","Keep reps low and output high; do not let the card become conditioning.","Prioritize non-traditional strength expression: jumps, starts, throws, contacts, reaction, and projection over heavy implements."]}'::jsonb,
  updated_at = now()
WHERE slug = 'light-sled-sprint-push';

