-- Partner Chase First-Step Sprint (partner-chase-first-step-sprint)
UPDATE coaching.exercise SET
  name = 'Partner Chase First-Step Sprint',
  description = 'Partner Chase First-Step Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.',
  card_summary = 'Partner Chase First-Step Sprint trains live first-step acceleration under a simple chase stimulus. Use it when the session needs fresh explosiveness rather than loaded strength volume.',
  coach_language = 'Primary subrole: Reactive Agility / Tumbling Output. Slot: reactive first step. Coach Partner Chase First-Step Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.',
  athlete_language = 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.',
  movement_family = 'Acceleration / First-Step Output',
  primary_phase_key = 'output',
  phase_subrole = 'reactive_agility_tumbling_output',
  primary_order_slot = 'reactive_first_step',
  default_sets = 3,
  default_reps = 3,
