-- Rotational Bound to Stick (rotational-bound-to-stick)
UPDATE coaching.exercise SET
  name = 'Rotational Bound to Stick',
  description = 'Rotational Bound to Stick is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.',
  card_summary = 'Rotational Bound to Stick trains diagonal or rotational projection with a controlled finish. Use it when the session needs fresh explosiveness rather than loaded strength volume.',
  coach_language = 'Primary subrole: Deceleration / COD Power. Slot: rotational power. Coach Rotational Bound to Stick as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.',
  athlete_language = 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.',
  movement_family = 'Rotational / Diagonal Power',
  primary_phase_key = 'output',
  phase_subrole = 'deceleration_cod_power',
  primary_order_slot = 'rotational_power',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = 12,
  default_rest_seconds = 120,
  est_seconds_per_set = 135,
  movement_requirements = '{"primary_joint_actions":["hip_rotation","thoracic_rotation","trunk_bracing","hip_extension","knee_extension","ankle_plantar_flexion"],"primary_tissues":["glutes","hamstrings","hip_flexors","abdominals","obliques","spinal_erectors"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Rotational Bound to Stick is an Output-phase explosiveness drill for diagonal or rotational projection with a controlled finish. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Clear the landing area and use a stable, non-slip surface.","Start with the lowest amplitude version that allows quiet contacts and clean alignment.","Place cones, box, line, or target only as needed for the variation."],"execution_steps":["Load only as much as needed to create a fast takeoff or contact.","Explode through the floor with the intended direction and posture.","Land, rebound, or stick according to the drill; end the rep the moment alignment or contact quality drops."],"coach_cues":["Project, then own the brake.","Knee tracks over foot.","Hips and chest stay organized.","Burst out clean.","Rotational Bound to Stick: quality beats quantity."],"breathing_cues":["Brace before the explosive effort.","Exhale naturally through the burst; do not hold breath across repeated reps.","Use the walk-back or reset time to restore calm breathing."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."],"quality_gate":["Rep looks fast, crisp, and intentional from start to finish.","Athlete can explain the target direction, cue, or landing outcome.","No pain, no uncontrolled collapse, and no visible drop-off in speed across the set.","Contacts are quiet and alignment stays consistent."],"stop_signs":["Pain, limping, dizziness, or apprehension.","Ground contacts become loud, slow, or unstable.","Athlete cannot recover enough to produce another high-speed rep."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Heavy lower-body strength","Acceleration sprints","Sport skill work","Conditioning block"],"pairs_well_after":["Dynamic warm-up","Landing prep","Sprint mechanics","Trunk activation"],"good_for_sessions":["deceleration","court_field_power","power_development"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears during takeoff, landing, sprinting, throwing, bracing, or contact.","Athlete cannot control the lower-level version.","The session already created enough fatigue that speed or landing quality is compromised.","Coach intends to use the drill as conditioning instead of Output."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex explosiveness demo recommended","Vortex Exercise Card Authoring Guide: Output sequencing and dose rules","NSCA-style plyometric, sprint, and medicine-ball technique reference"],"internal_notes":["Film Rotational Bound to Stick from front/side where useful.","Keep reps low and output high; do not let the card become conditioning.","Prioritize non-traditional strength expression: jumps, starts, throws, contacts, reaction, and projection over heavy implements."]}'::jsonb,
  updated_at = now()
WHERE slug = 'rotational-bound-to-stick';

