-- Medicine Ball Side Toss with Step (medicine-ball-side-toss-with-step)
UPDATE coaching.exercise SET
  name = 'Medicine Ball Side Toss with Step',
  description = 'Medicine Ball Side Toss with Step is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.',
  card_summary = 'Medicine Ball Side Toss with Step trains step-in rotational throw with sequencing and momentum. Use it when the session needs fresh explosiveness rather than loaded strength volume.',
  coach_language = 'Primary subrole: Jump / Throw Explosive Power. Slot: rotational throw power. Coach Medicine Ball Side Toss with Step as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.',
  athlete_language = 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.',
  movement_family = 'Medicine Ball / Rotational Power',
  primary_phase_key = 'output',
  phase_subrole = 'jump_throw_explosive_power',
  primary_order_slot = 'rotational_throw_power',
  default_sets = 3,
  default_reps = 4,
  default_work_seconds = 12,
  default_rest_seconds = 90,
  est_seconds_per_set = 105,
  movement_requirements = '{"primary_joint_actions":["hip_rotation","thoracic_rotation","trunk_bracing","hip_extension","knee_drive","ankle_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","abdominals","obliques","spinal_erectors"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"high","impact_level":1}'::jsonb,
  coaching_execution = '{"movement_description":"Medicine Ball Side Toss with Step is an Output-phase explosiveness drill for step-in rotational throw with sequencing and momentum. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Choose a medicine ball light enough to throw fast without strain.","Use a safe wall, open field, or trained partner target with clear space.","Set the athlete in the start position specified by the drill and confirm trunk control before the first throw."],"execution_steps":["Load the hips and trunk in the start position without pausing too long.","Explode through the ground and trunk, then release the ball with maximal speed.","Finish balanced, retrieve the ball, and rest until the next rep can be equally fast."],"coach_cues":["Load fast, explode faster.","Throw or jump with intent.","Own the finish.","Rest until the next rep is sharp.","Medicine Ball Side Toss with Step: quality beats quantity."],"breathing_cues":["Brace before the explosive effort.","Exhale naturally through the burst; do not hold breath across repeated reps.","Use the walk-back or reset time to restore calm breathing."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version.","Using a ball so heavy that the throw becomes slow strength work."],"quality_gate":["Rep looks fast, crisp, and intentional from start to finish.","Athlete can explain the target direction, cue, or landing outcome.","No pain, no uncontrolled collapse, and no visible drop-off in speed across the set.","Ball speed stays high without spine leakage or shoulder irritation."],"stop_signs":["Pain, limping, dizziness, or apprehension.","Ball speed drops, trunk leaks, or the throw becomes a slow heave.","Athlete cannot recover enough to produce another high-speed rep."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Heavy upper-body strength","Acceleration sprints","Sport skill work","Conditioning block"],"pairs_well_after":["Dynamic warm-up","Landing prep","Sprint mechanics","Trunk activation"],"good_for_sessions":["power_development","upper_body_power"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears during takeoff, landing, sprinting, throwing, bracing, or contact.","Athlete cannot control the lower-level version.","The session already created enough fatigue that speed or landing quality is compromised.","Coach intends to use the drill as conditioning instead of Output."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex explosiveness demo recommended","Vortex Exercise Card Authoring Guide: Output sequencing and dose rules","NSCA-style plyometric, sprint, and medicine-ball technique reference"],"internal_notes":["Film Medicine Ball Side Toss with Step from front/side where useful.","Keep reps low and output high; do not let the card become conditioning.","Prioritize non-traditional strength expression: jumps, starts, throws, contacts, reaction, and projection over heavy implements."]}'::jsonb,
  updated_at = now()
WHERE slug = 'medicine-ball-side-toss-with-step';

