  default_rest_seconds = 120,
  est_seconds_per_set = 135,
  movement_requirements = '{"primary_joint_actions":["shoulder_horizontal_flexion","elbow_extension","trunk_bracing","rib_pelvis_stack","trunk_stiffness","hip_knee_ankle_absorption"],"primary_tissues":["pectorals","deltoids","serratus_anterior","forearms","abdominals","obliques"],"breathing_demand":"braced_exhale","balance_demand":"dynamic","coordination_demand":"moderate","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Plyo Push-Up is an Output-phase explosiveness drill for explosive pressing with shoulder and trunk stiffness. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Clear the landing area and use a stable, non-slip surface.","Start with the lowest amplitude version that allows quiet contacts and clean alignment.","Place cones, box, line, or target only as needed for the variation."],"execution_steps":["Start in a strong push-up position with ribs and pelvis stacked.","Lower under control just enough to spring out aggressively.","Push the floor away explosively, land through the hands, reset, and stop before posture changes."],"coach_cues":["Load fast, explode faster.","Throw or jump with intent.","Own the finish.","Rest until the next rep is sharp.","Plyo Push-Up: quality beats quantity."],"breathing_cues":["Brace before the explosive effort.","Exhale naturally through the burst; do not hold breath across repeated reps.","Use the walk-back or reset time to restore calm breathing."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version."],"quality_gate":["Rep looks fast, crisp, and intentional from start to finish.","Athlete can explain the target direction, cue, or landing outcome.","No pain, no uncontrolled collapse, and no visible drop-off in speed across the set.","Contacts are quiet and alignment stays consistent."],"stop_signs":["Pain, limping, dizziness, or apprehension.","Ground contacts become loud, slow, or unstable.","Athlete cannot recover enough to produce another high-speed rep."]}'::jsonb,
