-- Reaction Ball Drop Sprint (reaction-ball-drop-sprint)
UPDATE coaching.exercise SET
  name = 'Reaction Ball Drop Sprint',
  description = 'Reaction Ball Drop Sprint is a non-traditional strength-based explosiveness drill selected for athletes who need to express force quickly: football linemen off the line, sprinters from a start, baseball hitters and throwers, jumpers, and field/court athletes. The goal is high-output movement quality with low fatigue, not strength grinding or conditioning volume.',
  card_summary = 'Reaction Ball Drop Sprint trains visual reaction into explosive first-step acceleration. Use it when the session needs fresh explosiveness rather than loaded strength volume.',
  coach_language = 'Primary subrole: Reactive Agility / Tumbling Output. Slot: reactive first step. Coach Reaction Ball Drop Sprint as Output work: high intent, low total volume, full recovery, and immediate stop when speed, posture, contact quality, or landing ownership drops.',
  athlete_language = 'Move fast, stay sharp, and own the finish. This is not a burnout set; every rep should look explosive and athletic.',
  movement_family = 'Reactive Explosiveness',
