  phase_subrole = 'reactive_agility_tumbling_output',
  primary_order_slot = 'reactive_first_step',
  default_sets = 3,
  default_reps = 3,
  default_work_seconds = 8,
  default_rest_seconds = 90,
  est_seconds_per_set = 105,
  movement_requirements = '{"primary_joint_actions":["hip_extension","knee_drive","ankle_stiffness","rib_pelvis_stack","trunk_stiffness"],"primary_tissues":["glutes","hamstrings","hip_flexors","calves","achilles_tendon","foot_intrinsics"],"breathing_demand":"rhythmic_braced","balance_demand":"reactive_dynamic","coordination_demand":"high","impact_level":2}'::jsonb,
  coaching_execution = '{"movement_description":"Reaction Ball Drop Sprint is an Output-phase explosiveness drill for visual reaction into explosive first-step acceleration. The athlete performs it fresh, with maximal intent, clean positions, and enough rest that every rep stays fast.","setup":["Set a short reaction lane with cones and one clear start line.","Define the cue, finish point, and reset rule before the set starts.","Keep the stimulus simple enough that the athlete can react explosively without guessing or drifting."],"execution_steps":["Hold the start position until the live cue appears.","React with the first purposeful step rather than rocking or false stepping.","Accelerate, bound, or redirect through the assigned finish, then walk back and fully reset."],"coach_cues":["See it, go.","No guessing step.","Explode after the cue.","Reset fully.","Reaction Ball Drop Sprint: quality beats quantity."],"breathing_cues":["Brace before the explosive effort.","Exhale naturally through the burst; do not hold breath across repeated reps.","Use the walk-back or reset time to restore calm breathing."],"common_faults":["Turning the drill into conditioning by adding too many reps or too little rest.","Counting reps after speed, posture, or landing/contact quality has dropped.","Chasing height, distance, or chaos before the athlete owns the basic version.","Making the cue so complex that the athlete hesitates instead of reacting explosively."],"quality_gate":["Rep looks fast, crisp, and intentional from start to finish.","Athlete can explain the target direction, cue, or landing outcome.","No pain, no uncontrolled collapse, and no visible drop-off in speed across the set.","Athlete reacts to the cue without pre-jumping or guessing."],"stop_signs":["Pain, limping, dizziness, or apprehension.","Ground contacts become loud, slow, or unstable.","Athlete cannot recover enough to produce another high-speed rep."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Heavy lower-body strength","Acceleration sprints","Sport skill work","Conditioning block"],"pairs_well_after":["Dynamic warm-up","Landing prep","Sprint mechanics","Trunk activation"],"good_for_sessions":["reactive_agility","court_field_power","power_development"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears during takeoff, landing, sprinting, throwing, bracing, or contact.","Athlete cannot control the lower-level version.","The session already created enough fatigue that speed or landing quality is compromised.","Coach intends to use the drill as conditioning instead of Output."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex explosiveness demo recommended","Vortex Exercise Card Authoring Guide: Output sequencing and dose rules","NSCA-style plyometric, sprint, and medicine-ball technique reference"],"internal_notes":["Film Reaction Ball Drop Sprint from front/side where useful.","Keep reps low and output high; do not let the card become conditioning.","Prioritize non-traditional strength expression: jumps, starts, throws, contacts, reaction, and projection over heavy implements."]}'::jsonb,
