  fit_weight = 5,
  freshness_required = TRUE,
  fatigue_sensitivity = 5,
  fatigue_cost = 4,
  technical_complexity = 4,
  impact_level = 2,
  intensity_ceiling = 'high',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'output'
JOIN coaching.phase_order_slot pos ON pos.key = 'reactive_first_step' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'auditory-start-sprint';

INSERT INTO coaching.exercise_phase_profile (
  exercise_id, phase_id, fit_weight, role, order_slot, order_index,
  freshness_required, fatigue_sensitivity, fatigue_cost, technical_complexity, impact_level, intensity_ceiling
)
SELECT e.id, sp.id, 5, 'primary', 'reactive_first_step', pos.order_index,
  TRUE, 5, 4,
  4, 2, 'high'
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'output'
JOIN coaching.phase_order_slot pos ON pos.key = 'reactive_first_step' AND pos.phase_id = sp.id
WHERE e.slug = 'auditory-start-sprint'
  AND NOT EXISTS (
    SELECT 1 FROM coaching.exercise_phase_profile ep
    WHERE ep.exercise_id = e.id AND ep.phase_id = sp.id
  );

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'attempts',
  default_sets = 3,
  default_reps = 3,
  default_distance = NULL,
  default_work_seconds = 8,
  default_rest_seconds = 90,
  est_seconds_per_set = 105,
  default_rpe_min = 7,
  default_rpe_max = 9,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'auditory-start-sprint';

INSERT INTO coaching.exercise_dosage_profile (
  exercise_id, profile_name, is_default, volume_unit, default_sets, default_reps,
  default_work_seconds, default_rest_seconds, default_distance, est_seconds_per_set, default_rpe_min, default_rpe_max
)
SELECT e.id, 'Default', TRUE, 'attempts', 3, 3,
  8, 90, NULL::integer,
  105, 7, 9
FROM coaching.exercise e
WHERE e.slug = 'auditory-start-sprint'
  AND NOT EXISTS (SELECT 1 FROM coaching.exercise_dosage_profile dp WHERE dp.exercise_id = e.id AND dp.profile_name = 'Default');

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = 3,
  minimum_hours_between_hard_exposures = 24,
  counts_as_high_intensity = TRUE,
  counts_as_high_impact = FALSE,
  counts_as_neural = TRUE,
  counts_as_tissue_stress = TRUE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'auditory-start-sprint';

INSERT INTO coaching.exercise_regimen_rule (
  exercise_id, can_be_daily, weekly_max_frequency, minimum_hours_between_hard_exposures,
  counts_as_high_intensity, counts_as_high_impact, counts_as_neural, counts_as_tissue_stress, counts_as_conditioning
)
SELECT e.id,
  FALSE, 3, 24,
  TRUE, FALSE, TRUE,
  TRUE, FALSE
FROM coaching.exercise e
