  AND NOT EXISTS (SELECT 1 FROM coaching.exercise_regimen_rule rr WHERE rr.exercise_id = e.id);

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 2,
  impact_level = 2,
  requires_spotting = FALSE,
  requires_coach_supervision = 'required',
  readiness_checks = ARRAY['Pain-free dynamic warm-up and movement prep completed.', 'Athlete can demonstrate the lower-level version with control.', 'Coach can provide enough rest and space for high-quality output.']::text[],
  contraindications = ARRAY['Pain with the selected takeoff, landing, throw, sprint, or brace position.', 'Uncontrolled joint alignment at a lower progression.', 'Athlete is too fatigued to keep reps crisp.']::text[],
  common_substitutions = ARRAY['Predictable first-step start', 'Coach-count start sprint', 'Low-intensity mirror walk']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'auditory-start-sprint';

INSERT INTO coaching.exercise_safety_profile (
  exercise_id, risk_level, impact_level, requires_spotting, requires_coach_supervision,
  readiness_checks, contraindications, common_substitutions
)
SELECT e.id, 2, 2, FALSE,
  'required',
  ARRAY['Pain-free dynamic warm-up and movement prep completed.', 'Athlete can demonstrate the lower-level version with control.', 'Coach can provide enough rest and space for high-quality output.']::text[], ARRAY['Pain with the selected takeoff, landing, throw, sprint, or brace position.', 'Uncontrolled joint alignment at a lower progression.', 'Athlete is too fatigued to keep reps crisp.']::text[], ARRAY['Predictable first-step start', 'Coach-count start sprint', 'Low-intensity mirror walk']::text[]
FROM coaching.exercise e
WHERE e.slug = 'auditory-start-sprint'
