-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for explosiveness: rapid force expression without loaded strength grinding.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('falling-start-sprint', 'Directly transfers to track starts, linemen firing off the line, and any athlete who must convert lean into projection. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('2-point-acceleration-start', 'A clean general-purpose first-step drill for field, court, and track athletes without needing blocks. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('half-kneeling-sprint-start', 'Useful when athletes need to explode from the ground or from a compromised stance while keeping trunk stiffness. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('push-up-start-sprint', 'Links a fast push from the floor to sprint acceleration, valuable for football, wrestling, baseball, and chaotic field sport starts. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('prone-pop-up-to-sprint', 'Develops explosive transition from ground contact to acceleration without turning it into conditioning burpees. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('wall-drive-switch-to-sprint', 'Bridges wall-drive mechanics to live sprinting and helps athletes feel shin angle, knee punch, and hip extension. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('light-sled-sprint-push', 'Gives linemen and sprinters a forceful projection drill without making the sled a slow strength grind. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('partner-chase-first-step-sprint', 'Adds intent and reaction while preserving the training goal: win the first step, not survive repeated conditioning reps. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('pogo-jumps', 'Builds the foot-ankle stiffness needed for sprinting, jumping, and quick reactivity without heavy loading. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
  ('line-hops', 'Simple, scalable elastic work that trains short ground contact and foot speed in multiple directions. It targets rapid force expression, neural drive, timing, and stiffness while avoiding the slow grind of traditional strength exercises.', 'Belongs in Output because the adaptation depends on freshness, intent, speed, and clean execution. If fatigue changes mechanics, the drill has shifted toward conditioning rather than explosiveness.', 'Place after Prepare & Access and any necessary Movement Intelligence, before heavy strength, conditioning, long sport blocks, or fatigue-heavy circuits. Use full rest so every rep stays explosive.', 'The common error is using the drill as a finisher, conditioning station, or high-rep challenge. Stop before power drops; do not chase fatigue, heavy load, random chaos, or more contacts after quality fades.', 'Scale by movement quality first: reduce impact, range, distance, speed, reaction demand, implement weight, or number of contacts before adding complexity. Progress only when output stays fast and repeatable.'),
